import React, { useState, useEffect, useRef } from 'react';
import 'src/views/BookReader.css';

const CONFIG = { friction: 0.88, velocityMult: 1.8, maxZoom: 6.0 };
const DB_NAME = "LinkUpBooks";
const STORE_NAME = "content_cache";

const BookReader = ({ book, onClose }) => {
    const [loading, setLoading] = useState(true);
    const [iframeSrc, setIframeSrc] = useState(null);
    const [isUiVisible, setIsUiVisible] = useState(true);
    const [isFabActive, setIsFabActive] = useState(false);
    const [currentTheme, setCurrentTheme] = useState('light');
    const [contextMenu, setContextMenu] = useState(null); // { x, y, text }
    const [mironInsight, setMironInsight] = useState(null); // { x, y, text, conversation: [] }
    const [insightInput, setInsightInput] = useState('');
    const [isInsightTyping, setIsInsightTyping] = useState(false);

    // Dragging state
    const [isInsightTyping, setIsInsightTyping] = useState(false);

    // Dragging state
    const dragOffset = useRef({ x: 0, y: 0 });
    const popoverRef = useRef(null);
    const ctxMenuRef = useRef(null);
    const [isDraggingPopover, setIsDraggingPopover] = useState(false);
    const [isDraggingCtx, setIsDraggingCtx] = useState(false);
    const viewportRef = useRef(null);
    const iframeRef = useRef(null);
    const layerRef = useRef(null);
    const requestRef = useRef(null);
    const sliderRef = useRef(null);
    const pageCountRef = useRef(null);

    // Physics State
    const state = useRef({ x: 0, y: 0, scale: 1 });
    const velocity = useRef({ x: 0, y: 0 });
    const contentDims = useRef({ width: 0, height: 0 });
    const minScaleLimit = useRef(1.0);

    // Input State
    const input = useRef({
        isSliderDragging: false,
        isDragging: false,
        startX: 0, startY: 0,
        lastX: 0, lastY: 0,
        lastTime: 0,
        initialPinchDist: 0,
        initialScale: 1,
        dragTotalDistance: 0,
        touchStartTime: 0,
        lastFlickTime: 0,
        boostLevel: 1
    });

    // IndexedDB Helper
    const getDB = () => new Promise((resolve, reject) => {
        const request = indexedDB.open(DB_NAME, 1);
        request.onupgradeneeded = () => request.result.createObjectStore(STORE_NAME);
        request.onsuccess = () => resolve(request.result);
        request.onerror = () => reject(request.error);
    });

    // Fetch Book Data with Caching
    useEffect(() => {
        const fetchBook = async () => {
            console.log("[READER] Cache Check for:", book.path);
            try {
                setLoading(true);
                const db = await getDB();

                // 1. Check Cache
                const cachedBlob = await new Promise((resolve) => {
                    const transaction = db.transaction(STORE_NAME, "readonly");
                    const request = transaction.objectStore(STORE_NAME).get(book.path);
                    request.onsuccess = () => resolve(request.result);
                });

                if (cachedBlob) {
                    console.log("[READER] Serving from Local Storage (Offline)");
                    setIframeSrc(URL.createObjectURL(cachedBlob));
                    setLoading(false);
                    return;
                }

                // 2. Network Fallback
                console.log("[READER] Cache Miss. Fetching from Network...");
                const response = await fetch('https://xvldfsmxskhemkslsbym.supabase.co/functions/v1/book-reader', {
                    method: 'POST',
                    headers: { 'Content-Type': 'application/json' },
                    body: JSON.stringify({ 
                        action: 'get_book_compressed',
                        book_path: book.path
                    })
                });

                if (!response.ok) throw new Error("Failed to fetch book");

                const blob = await response.blob();

                // 3. Save to Cache for next time
                const saveTx = db.transaction(STORE_NAME, "readwrite");
                saveTx.objectStore(STORE_NAME).put(blob, book.path);

                setIframeSrc(URL.createObjectURL(blob));
            } catch (error) {
                console.error("Error loading book:", error);
                alert("Failed to load book content.");
                onClose();
            } finally {
                setLoading(false);
            }
        };

        if (book?.path) fetchBook();

        return () => {
            if (iframeSrc) URL.revokeObjectURL(iframeSrc);
        };
    }, [book]);

    // Handle interactions inside the iframe (since buttons are injected HTML)
    useEffect(() => {
        const handleIframeClick = (e) => {
            const target = e.target;
            console.log("[IFRAME_CLICK]", target.tagName, target.className);
            if (target.classList.contains('q-opt-btn')) {
                // Visual feedback for selection
                const parent = target.parentElement;
                parent.querySelectorAll('.q-opt-btn').forEach(btn => btn.style.borderColor = 'rgba(255,255,255,0.1)');
                target.style.borderColor = '#42d7b8';
                target.style.background = 'rgba(66, 215, 184, 0.1)';
            }
            if (target.classList.contains('q-submit')) {
                target.innerText = "Correct! +5 Linkoins";
                target.style.background = "#b1d34b";
                // Future: Call Supabase to increment balance
            }
        };

        const iframe = document.getElementById('book-iframe');
        if (iframe) {
            iframe.contentWindow.addEventListener('click', handleIframeClick);
        }
        return () => {
            if (iframe && iframe.contentWindow) iframe.contentWindow.removeEventListener('click', handleIframeClick);
        };
    }, [iframeSrc]);

    // Handle Iframe Load & Sizing
    const handleIframeLoad = (e) => {
        console.log("[IFRAME] Content Loaded");
        const iframe = e.target;
        iframeRef.current = iframe;

        // Small delay to ensure the blob document is fully parsed by the browser
        setTimeout(() => {
            try {
                const doc = iframe.contentDocument || iframe.contentWindow.document;
                if (!doc) return;

                const docBody = doc.body;
                const docEl = doc.documentElement;

                // Standardize the iframe internal layout
                docBody.style.margin = '0';
                docBody.style.padding = '0';
                docBody.style.overflow = 'hidden';

                // Measure the actual full content size - MOVE THIS UP TO AVOID REFERENCE ERROR
                const w = Math.max(docBody.scrollWidth, docBody.offsetWidth, docEl.clientWidth, docEl.scrollWidth);
                const h = Math.max(docBody.scrollHeight, docBody.offsetHeight, docEl.clientHeight, docEl.scrollHeight);

                // --- DOCUMENT-RELATIVE SCALING ---
                // We no longer divide by fitScale. By using a fixed size (e.g. 22px),
                // the question text will scale proportionally with the book's native text
                // through the iframe's CSS transform scale.
                const baseFontSize = 22; 

                const style = doc.createElement('style');
                style.textContent = `
                    @import url('https://fonts.googleapis.com/css2?family=Poppins:wght@500;700&display=swap');

                    /* --- THEME ENGINE --- */
                    body { 
                        transition: background-color 0.3s ease, color 0.3s ease; 
                        min-width: ${w}px; /* Prevent body collapse */
                    }

                    /* Dark Theme */
                    body.theme-dark, 
                    body.theme-dark .page, 
                    body.theme-dark .page-container, 
                    body.theme-dark .text-container {
                        background-color: #121212 !important;
                        color: #d0d0d0 !important;
                    }
                    body.theme-dark span, 
                    body.theme-dark p, 
                    body.theme-dark div {
                        color: #d0d0d0 !important;
                        background-color: transparent !important;
                    }
                    body.theme-dark img { opacity: 0.85; mix-blend-mode: normal; }

                    /* Sepia Theme */
                    body.theme-sepia, 
                    body.theme-sepia .page, 
                    body.theme-sepia .page-container {
                        background-color: #f4ecd8 !important;
                        color: #5b4636 !important;
                    }
                    body.theme-sepia span, 
                    body.theme-sepia p {
                        color: #5b4636 !important;
                        background-color: transparent !important;
                    }
                    body.theme-sepia .miron-question-card {
                        background: #eaddcf !important;
                        border-color: #d3c4b1 !important;
                        color: #5b4636 !important;
                    }
                    body.theme-sepia .q-label { color: #8a6a4b !important; }
                    body.theme-sepia .miron-orb-mini { background: #8a6a4b !important; }
                    body.theme-sepia .q-opt-btn { background: rgba(91, 70, 54, 0.05) !important; border-color: rgba(91, 70, 54, 0.15) !important; color: #5b4636 !important; }
                    body.theme-sepia .q-submit { background: #8a6a4b !important; color: #f4ecd8 !important; }
                    body.theme-sepia .q-match-item {
                        background: rgba(91, 70, 54, 0.05) !important;
                        border-color: rgba(91, 70, 54, 0.2) !important;
                        color: #5b4636 !important;
                    }
                    body.theme-sepia .q-column-b .q-match-item {
                        background: rgba(138, 106, 75, 0.1) !important;
                        border-color: #8a6a4b !important;
                    }

                    /* The Root Container sets the Base Font Size */
                    .miron-portal-container {
                        /* Align with the book'https://esm.sh/s internal text margins (approx 110px in Cowb.html) */
                        width: calc(100% - 220px); 
                        margin: 4em 110px;
                        font-family: 'Poppins', sans-serif;
                        font-size: ${baseFontSize}px; 
                        position: relative;
                        z-index: 100;
                        box-sizing: border-box;
                    }

                    /* All children use 'em' to scale relative to the dynamic base */
                    .miron-question-card {
                        background: #1a1a1a;
                        border: 1px solid rgba(66, 215, 184, 0.3);
                        border-radius: 1.5em;
                        padding: 2em;
                        box-shadow: 0 1em 3em rgba(0,0,0,0.6);
                        color: #e0e0e0;
                    }
                    .q-header {
                        display: flex;
                        align-items: center;
                        margin-bottom: 1.5em;
                        gap: 0.75em;
                    }
                    .miron-orb-mini {
                        width: 1em;
                        height: 1em;
                        background: #42d7b8;
                        border-radius: 50%;
                        box-shadow: 0 0 0.8em rgba(66, 215, 184, 0.6);
                    }
                    .q-label {
                        color: #42d7b8;
                        font-weight: 700;
                        letter-spacing: 0.1em;
                        font-size: 0.85em; 
                        text-transform: uppercase;
                    }
                    .q-points-badge {
                        margin-left: auto;
                        font-size: 0.75em;
                        opacity: 0.6;
                        font-family: monospace;
                    }
                    .q-text {
                        font-size: 1.3em; 
                        line-height: 1.5;
                        margin-bottom: 1.2em;
                        font-weight: 500;
                    }
                    .q-media-content {
                        width: 100%;
                        border-radius: 1em;
                        margin-bottom: 1.5em;
                        border: 1px solid rgba(255,255,255,0.1);
                        display: block;
                    }
                    /* Matching Layout */
                    .q-matching-container {
                        display: grid;
                        grid-template-columns: 1fr 1fr;
                        gap: 1em;
                        margin-bottom: 1.5em;
                    }
                    .q-match-column {
                        display: flex;
                        flex-direction: column;
                        gap: 0.6em;
                    }
                    .q-match-item {
                        padding: 0.8em 1em;
                        border-radius: 0.6em;
                        font-size: 0.9em;
                        background: rgba(255,255,255,0.03);
                        border: 1px dashed rgba(255,255,255,0.1);
                        min-height: 3em;
                        display: flex;
                        align-items: center;
                    }
                    .q-column-b .q-match-item {
                        border-style: solid;
                        border-color: rgba(66, 215, 184, 0.2);
                        background: rgba(66, 215, 184, 0.02);
                    }
                    .q-options {
                        display: flex;
                        flex-direction: column;
                        gap: 0.75em;
                    }
                    .q-opt-btn {
                        background: rgba(255,255,255,0.05);
                        border: 2px solid rgba(255,255,255,0.1);
                        padding: 1em 1.25em;
                        border-radius: 0.8em;
                        color: #fff;
                        font-size: 1em;
                        font-family: inherit;
                        text-align: left;
                        cursor: pointer;
                        transition: all 0.2s;
                    }
                    .q-opt-btn:active, .q-opt-btn:hover {
                        background: rgba(66, 215, 184, 0.1);
                        border-color: #42d7b8;
                    }
                    .q-submit {
                        margin-top: 1.5em;
                        width: 100%;
                        padding: 1em;
                        background: #42d7b8;
                        color: #0c0c0c;
                        font-weight: 700;
                        font-size: 1.1em;
                        font-family: inherit;
                        border: none;
                        border-radius: 0.8em;
                        cursor: pointer;
                        box-shadow: 0 0.25em 1em rgba(66, 215, 184, 0.4);
                    }

                    /* --- SMART HIGHLIGHT --- */
                    ::highlight(sentence-focus) {
                        background-color: #fde047;
                        color: #000;
                    }
                `;
                doc.head.appendChild(style);

                // Apply initial theme
                doc.body.className = `theme-${currentTheme}`;

                contentDims.current = { width: w, height: h };

                const mironCount = doc.querySelectorAll('.miron-question-card').length;
                console.log(`[IFRAME] Dimensions: ${w}x${h}. Miron Challenges detected: ${mironCount}`);

                if (layerRef.current) {
                    layerRef.current.style.width = `${w}px`;
                    layerRef.current.style.height = `${h}px`;
                }

                // Calculate initial scale to fit width
                const vw = window.innerWidth;
                minScaleLimit.current = vw / w;
                state.current.scale = minScaleLimit.current;

                // Centering initial view
                state.current.x = 0;
                state.current.y = 0;

                console.log("Book Content Initialized:", w, "x", h);

                // --- SMART SENTENCE LOGIC (PASS-THROUGH) ---
                // We expose this function so the parent component can call it 
                // even though the iframe has pointer-events: none
                const win = iframe.contentWindow;

                win.highlightAt = (clientX, clientY) => {
                    if (!win.CSS || !win.CSS.highlights) return false;

                    let range;
                    if (doc.caretRangeFromPoint) {
                        range = doc.caretRangeFromPoint(clientX, clientY);
                    } else if (doc.caretPositionFromPoint) {
                        const pos = doc.caretPositionFromPoint(clientX, clientY);
                        range = doc.createRange();
                        range.setStart(pos.offsetNode, pos.offset);
                        range.collapse(true);
                    }

                    // Rule 1: Prevent interaction with Question Cards
                    const targetNode = range?.startContainer;
                    const targetElement = targetNode?.nodeType === 3 ? targetNode.parentElement : targetNode;
                    if (targetElement?.closest('.miron-portal-container')) {
                        win.CSS.highlights.clear();
                        return false;
                    }

                    // Check if we hit valid text content
                    if (!range || !docBody.contains(targetNode)) {
                        win.CSS.highlights.clear();
                        return false;
                    }
                    if (targetNode.nodeType !== 3) {
                        win.CSS.highlights.clear();
                        return false;
                    }

                    // Rule 2: Bound to Page (Find closest container that is NOT the body)
                    const pageBoundary = targetElement.closest('.page, .page-container, .text-container') || docBody;

                    const sentenceRange = findSentenceRange(doc, targetNode, range.startOffset, pageBoundary);
                    if (sentenceRange) {
                        // Apply Highlight
                        const highlight = new win.Highlight(sentenceRange);
                        win.CSS.highlights.set("sentence-focus", highlight);

                        // Return Metadata for Context Menu
                        const rect = sentenceRange.getBoundingClientRect();
                        return {
                            found: true,
                            text: sentenceRange.toString(),
                            rect: { x: rect.x, y: rect.y, width: rect.width, height: rect.height }
                        };
                    }

                    win.CSS.highlights.clear();
                    return { found: false };
                };

                function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
                    const sentenceEndRegex = /[.!?]/;

                    // Helper: TreeWalker for linear text traversal within the page
                    function createWalker(root) {
                        return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
                    }

                    // 1. BACKWARD SCAN (Find start)
                    let currentStartNode = startNode;
                    let currentStartOffset = startOffset;
                    let finalStartNode = startNode;
                    let finalStartOffset = 0;

                    let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
                    let lastPuncIndex = -1;
                    for(let i = textBefore.length - 1; i >= 0; i--) {
                        if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
                    }

                    if (lastPuncIndex !== -1) {
                        finalStartOffset = lastPuncIndex + 1;
                        if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
                    } else {
                        const walker = createWalker(pageBoundary);
                        walker.currentNode = currentStartNode;
                        let prevNode = walker.previousNode();
                        let foundStart = false;

                        while (prevNode && !foundStart) {
                            const text = prevNode.textContent;
                            for (let i = text.length - 1; i >= 0; i--) {
                                if (sentenceEndRegex.test(text[i])) {
                                    finalStartNode = prevNode; finalStartOffset = i + 1;
                                    if(text[finalStartOffset] === ' ') finalStartOffset++;
                                    foundStart = true; break;
                                }
                            }
                            if (!foundStart) {
                                finalStartNode = prevNode; finalStartOffset = 0;
                                prevNode = walker.previousNode();
                            }
                        }
                    }

                    // 2. FORWARD SCAN (Find end)
                    let currentEndNode = startNode;
                    let currentEndOffset = startOffset;
                    let finalEndNode = startNode;
                    let finalEndOffset = startNode.textContent.length;

                    let textAfter = currentEndNode.textContent.substring(currentEndOffset);
                    let nextPuncIndex = textAfter.search(sentenceEndRegex);

                    if (nextPuncIndex !== -1) {
                        finalEndOffset = currentEndOffset + nextPuncIndex + 1;
                    } else {
                        const walker = createWalker(pageBoundary);
                        walker.currentNode = currentEndNode;
                        let nextNode = walker.nextNode();
                        let foundEnd = false;

                        while (nextNode && !foundEnd) {
                            const text = nextNode.textContent;
                            const puncIdx = text.search(sentenceEndRegex);
                            if (puncIdx !== -1) {
                                finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
                                foundEnd = true;
                            } else {
                                finalEndNode = nextNode; finalEndOffset = text.length;
                                nextNode = walker.nextNode();
                            }
                        }
                    }

                    // Create the final Range
                    const r = rootDoc.createRange();
                    try {
                        r.setStart(finalStartNode, finalStartOffset);
                        r.setEnd(finalEndNode, finalEndOffset);
                        return r;
                    } catch (e) {
                        console.warn("Sentence Range Error:", e);
                        return null;
                    }
                }
            } catch (err) {
                console.error("Iframe Load Error:", err);
            }
        }, 100);
    };

    // Apply Theme Changes
    useEffect(() => {
        if (iframeRef.current) {
            const doc = iframeRef.current.contentDocument || iframeRef.current.contentWindow.document;
            if (doc && doc.body) {
                doc.body.className = `theme-${currentTheme}`;
            }
        }
    }, [currentTheme]);

    const toggleTheme = () => {
        const themes = ['light', 'sepia', 'dark'];
        const nextIndex = (themes.indexOf(currentTheme) + 1) % themes.length;
        setCurrentTheme(themes[nextIndex]);
        setIsFabActive(false);
    };

    const handleFitPage = () => {
        // Reset Zoom to Width Fit
        const currentRealY = state.current.y / state.current.scale;
        state.current.scale = minScaleLimit.current;
        state.current.x = 0;
        state.current.y = currentRealY * state.current.scale; // Maintain relative Y position
        velocity.current = { x: 0, y: 0 };
        setIsFabActive(false);
    };

    // --- OPTIMIZED PHYSICS ENGINE ---

    const applyConstraints = () => {
        const vw = window.innerWidth;
        const vh = window.innerHeight;
        const { width, height } = contentDims.current;
        const s = state.current;
        const v = velocity.current;

        const visualW = width * s.scale;
        const visualH = height * s.scale;

        // X Constraint
        if (visualW < vw) {
            s.x = (vw - visualW) / 2;
            v.x = 0;
        } else {
            if (s.x > 0) { s.x = 0; v.x = 0; }
            if (s.x < vw - visualW) { s.x = vw - visualW; v.x = 0; }
        }

        // Y Constraint
        if (visualH < vh) {
            s.y = (vh - visualH) / 2;
            v.y = 0;
        } else {
            if (s.y > 0) { s.y = 0; v.y = 0; }
            if (s.y < vh - visualH) { s.y = vh - visualH; v.y = 0; }
        }
    };

    // The Single Render Loop
    // Decouples input frequency from screen refresh rate for buttery smooth motion
    const loop = () => {
        // 1. Apply Physics if not dragging
        if (!input.current.isDragging) {
            const v = velocity.current;
            // Apply snap-stop: if velocity is low, kill it immediately
            if (Math.abs(v.x) < 0.5) v.x = 0;
            if (Math.abs(v.y) < 0.5) v.y = 0;

            if (v.x !== 0 || v.y !== 0) {
                v.x *= CONFIG.friction;
                v.y *= CONFIG.friction;
                state.current.x += v.x;
                state.current.y += v.y;
            }
        }

        // 2. Apply Constraints (Borders)
        applyConstraints();

        // 3. Render to DOM
        if (layerRef.current) {
            const { x, y, scale } = state.current;
            // Using transform3d for hardware acceleration
            layerRef.current.style.transform = `translate3d(${x}px, ${y}px, 0) scale(${scale})`;
        }

        // 4. Update UI (Slider & Pages)
        if (sliderRef.current && pageCountRef.current && contentDims.current.height > 0) {
            // Use Unscaled values for stability across Zoom levels
            const unscaledTotalH = contentDims.current.height;
            const unscaledY = Math.abs(state.current.y) / state.current.scale;
            const viewHeight = window.innerHeight / state.current.scale;

            // Slider Progress (0-100%)
            // We compare unscaled position against the maximum possible unscaled scroll
            const maxScroll = Math.max(1, unscaledTotalH - viewHeight);

            if (!input.current.isSliderDragging) {
                const progress = (unscaledY / maxScroll) * 100;
                sliderRef.current.value = Math.max(0, Math.min(100, progress));
            }

            // Page Count Logic (Standard Book Ratio 1.3)
            // This calculates pages based on content dimensions (like an ebook), not screen height.
            // It ensures the count is stable (doesn't change with zoom) and more accurate (higher count on mobile).
            const bookPageHeight = contentDims.current.width * 1.3;
            const totalPages = Math.max(1, Math.ceil(unscaledTotalH / bookPageHeight));

            // Calculate current page based on the top visible edge
            const currentPage = Math.min(totalPages, Math.max(1, Math.floor((unscaledY + (bookPageHeight * 0.3)) / bookPageHeight) + 1));

            pageCountRef.current.innerText = `${currentPage}/${totalPages}`;
        }

        // 5. Continue Loop
        requestRef.current = requestAnimationFrame(loop);
    };

    // --- CONTEXT MENU ACTIONS ---
    const handleMenuAction = (action) => {
        if (!contextMenu) return;
        const text = contextMenu.text;

        if (action === 'ask_miron') {
            // Calculate centered start position clamped to viewport
            const popWidth = 320;
            const popHeight = 400;
            const startX = Math.max(10, Math.min(window.innerWidth - popWidth - 10, contextMenu.x - (popWidth / 2)));
            const startY = Math.max(10, Math.min(window.innerHeight - popHeight - 20, contextMenu.y + 30));

            setMironInsight({
                x: startX,
                y: startY,
                text: text,
                conversation: [{
                    id: 1,
                    side: 'miron',
                    text: `Analyzing: "${text.substring(0, 40)}..."\n\nHow can I illuminate this for you?`,
                    thought: "Contextual neural mapping complete."
                }]
            });
        }
        if (action === 'copy') {
            navigator.clipboard.writeText(text);
        }
        setContextMenu(null);
    };

    const handleInsightSend = () => {
        if (!insightInput.trim() || !mironInsight) return;

        const userMsg = { id: Date.now(), side: 'user', text: insightInput };
        setMironInsight(prev => ({
            ...prev,
            conversation: [...prev.conversation, userMsg]
        }));
        setInsightInput('');
        setIsInsightTyping(true);

        // Simulate Miron response
        setTimeout(() => {
            setIsInsightTyping(false);
            const mironMsg = {
                id: Date.now() + 1,
                side: 'miron',
                text: "Based on the context of this document, this concept links directly to the later chapters on Entropy. Would you like a simplified breakdown?",
                thought: "Correlating chapter themes..."
            };
            setMironInsight(prev => ({
                ...prev,
                conversation: [...prev.conversation, mironMsg]
            }));
        }, 1500);
    };

    const handlePopoverDragStart = (e) => {
        if (!mironInsight) return;
        const clientX = e.clientX || (e.touches && e.touches[0].clientX);
