.app-link--recent .icon-wrapper { width: 48px; height: 48px; font-size: 1.2rem; }
.app-link--grid .icon-wrapper { width: 44px; height: 44px; font-size: 1.1rem; margin-bottom: 0.4rem; }
.app-label { font-size: 0.7rem; color: var(--text-secondary-dark); font-weight: 500; line-height: 1.2; }
.icon-color-1 { background: linear-gradient(45deg, #42d7b8, #1a9c8b); } .icon-color-2 { background: linear-gradient(45deg, #9b59b6, #7a3c9b); } .icon-color-3 { background: linear-gradient(45deg, #f1c40f, #c7a10d); } .icon-color-4 { background: linear-gradient(45deg, #e74c3c, #c0392b); } .icon-color-5 { background: linear-gradient(45deg, #3498db, #2980b9); } .icon-color-6 { background: linear-gradient(45deg, #52606d, #3e4c59); }

/* --- HOME TAB STYLES --- */
.hero-wrapper { position: relative; flex-shrink: 0; }
.app-header { position: absolute; top: 0; left: 0; right: 0; z-index: 10; display: flex; justify-content: space-between; align-items: center; padding: 1rem 1.5rem; }
.app-header .welcome-text h1 { font-size: 1.5rem; font-weight: 600; text-shadow: 0 1px 5px rgba(0,0,0,0.3); }
