.icon-orbiter .option:not(.active) .text-label { opacity: 0; max-width: 0; margin-left: -0.5rem; pointer-events: none; }
.icon-orbiter .option.active .icon-wrapper, .icon-orbiter .option.active .text-label { color: var(--accent-teal); }
.icon-orbiter .orbiter-indicator { position: absolute; top: 50%; left: 50%; transform: translate(-50%, -50%); width: 42px; height: 42px; border: 2px solid var(--accent-teal); border-radius: 50%; z-index: 1; opacity: 0; transition: opacity 0.3s ease; }
.icon-orbiter .option.active .orbiter-indicator { opacity: 1; }
.header-actions { display: flex; align-items: center; gap: 1rem; transition: opacity 0.3s; }
#connect-content .header-actions .profile-avatar { width: 36px; height: 36px; }
.pills-toggle-chevron { color: var(--text-secondary-dark); cursor: pointer; font-size: 1.2rem; transition: transform 0.3s ease, opacity 0.3s, visibility 0.3s; opacity: 0; visibility: hidden; }
.filter-pills-container { max-height: 0; opacity: 0; overflow: hidden; padding: 0 1rem; transition: all 0.4s cubic-bezier(0.4, 0, 0.2, 1); }
.filter-pills { display: flex; gap: 8px; overflow-x: auto; scrollbar-width: none; }
.chip { background-color: rgba(255, 255, 255, 0.1); border-radius: 20px; padding: 8px 16px; font-size: 0.85rem; font-weight: 500; white-space: nowrap; cursor: pointer; color: var(--text-secondary-dark); }
.chip.active { background-color: var(--accent-teal); color: var(--bg-dark); }
.app-container.header-collapsed .interactive-header { background: var(--bg-dark); }
