.story-card .title, .mission-card .title { font-size: 1.5rem; font-weight: 700; line-height: 1.3; }
.story-cta-btn { width: 100%; margin-top: 24px; background-color: rgba(0, 0, 0, 0.25); backdrop-filter: blur(5px); border: 1px solid rgba(255, 255, 255, 0.2); color: white; padding: 16px; border-radius: 12px; font-weight: 600; font-size: 1rem; cursor: pointer; display: flex; align-items: center; justify-content: center; gap: 8px; }
