        overflow-y: auto; /* Ensure content scrolls */
        scroll-behavior: smooth;
    }
    .page-content, .scrollable-content {
        height: auto;
        overflow: visible;
    }

    /* 3. HOME TAB GRID */
    #home-content .page-content {
        display: grid;
        grid-template-columns: repeat(12, 1fr);
        grid-template-rows: auto auto;
        gap: 2rem;
        max-width: 1400px;
        margin: 0 auto;
        width: 100%;
        padding-bottom: 4rem;
    }
    .hero-wrapper { max-width: 1400px; margin: 0 auto; width: 100%; padding: 2rem 2rem 0; }
    .welcome-hero { height: 260px; border-radius: 24px; }
    .priority-section { grid-column: span 8; margin: 0; }
    .priority-scroll-wrapper { overflow: visible; }
    .priority-track { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; padding: 0; }
    .priority-card { width: 100%; min-height: 160px; }
    .whats-next-section { grid-column: span 4; }
    .next-task-container { height: 100%; min-height: 160px; }

    /* 4. STUDY TAB & LIBRARY OVERLAY FIX */
    #study-content .study-hub-content {
        display: grid;
        grid-template-columns: repeat(12, 1fr);
        gap: 2rem;
        padding: 2rem;
        max-width: 1400px;
        margin: 0 auto;
        overflow: visible;
    }
    .study-header { flex-shrink: 0; padding: 1rem 2rem; max-width: 1400px; margin: 0 auto; width: 100%; }
    .library-preview-wrapper {
        grid-column: span 5;
        min-height: 400px;
        cursor: pointer;
        z-index: 10; /* Ensure it's clickable above backgrounds */
    }
    .library-preview-wrapper .vignette-bg { height: 100%; border-radius: 24px; }
    .study-section { display: contents; }
    .compact-trigger { grid-column: span 7; margin: 0; }
    .guidance-path { grid-column: span 7; margin-top: 1rem; }
    .observatory-widget { grid-column: span 5; margin-top: 2rem; }

    /* 5. CONNECT & PROFILE TABS */
    #connect-content .content-panel {
        overflow-y: auto;
        height: 100%;
        padding: 2rem;
    }
    #connect-content .interactive-header { max-width: 1200px; margin: 0 auto; width: 100%; }
    .messages-list { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; max-width: 1200px; margin: 0 auto; }

    #profile-content .scrollable-content { overflow-y: auto; height: 100%; }
    .profile-hero { height: 300px; display: flex; align-items: flex-end; padding-bottom: 2rem; }
    .portal-cards-container { display: grid; grid-template-columns: 1fr 1fr; gap: 2rem; max-width: 1200px; margin: 0 auto; padding: 0 2rem; }
    .settings-group { max-width: 1200px; margin: 2rem auto; padding: 0 2rem; padding-bottom: 4rem; }

    /* 6. OVERLAYS (MODALS) - ULTIMATE FIX */
    .fullscreen-overlay, .library-fullscreen, .pavilion-overlay {
        display: flex !important;
        align-items: center;
        justify-content: center;
        background-color: rgba(0, 0, 0, 0.85);
