const s = document.createElement('style'); s.textContent = `/* --- WIDE VIEW EXAM SESSION --- */
.exam-session-overlay {
    position: fixed;
    inset: 0;
    z-index: 3000;
    background-color: #050505;
    color: #e0e0e0;
    display: flex;
    flex-direction: column;
    font-family: 'Poppins', sans-serif;
    animation: sessionFadeIn 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

@keyframes sessionFadeIn { from { opacity: 0; transform: scale(1.02); } to { opacity: 1; transform: scale(1); } }

/* --- HEADER --- */
.session-header {
    padding: 1rem 1.5rem;
    display: flex;
    justify-content: space-between;
    align-items: center;
    background: rgba(5, 5, 5, 0.8);
    backdrop-filter: blur(20px); 
    border-bottom: 1px solid rgba(255, 255, 255, 0.08);
}

.session-title-box h1 {
    font-family: 'Newsreader', serif;
    font-size: 1.1rem;
    font-weight: 500;
    margin: 0;
}

.session-title-box p {
    font-size: 0.65rem;
    color: #707070;
    text-transform: uppercase;
    letter-spacing: 1px;
    margin: 0;
}

.timer-pill {
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.1);
    padding: 4px 12px;
    border-radius: 8px;
    font-family: 'Roboto Mono', monospace;
    font-size: 0.9rem;
    color: var(--accent-teal);
}

.timer-pill.urgent { color: #ff5f5f; border-color: rgba(255, 95, 95, 0.3); background: rgba(255, 95, 95, 0.05); }

.session-header-actions {
    display: flex;
    align-items: center;
    gap: 1rem;
}

.exit-session-btn {
    color: #fff;
    opacity: 0.5;
    transition: opacity 0.2s ease, transform 0.2s ease;
}

.exit-session-btn:hover {
    opacity: 1;
    transform: scale(1.1);
}

/* --- QUICK NAV STRIP --- */
.question-nav-strip {
    height: 50px;
    background: #0f0f0f;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    display: flex;
    align-items: center;
    gap: 10px;
    padding: 0 1.5rem;
    overflow-x: auto;
}

.question-nav-strip::-webkit-scrollbar { display: none; }

.nav-dot {
    min-width: 34px; height: 34px;
    border-radius: 10px;
    background: rgba(255, 255, 255, 0.03);
    border: 1px solid rgba(255, 255, 255, 0.08);
    display: flex; align-items: center; justify-content: center;
    font-size: 0.8rem; font-weight: 600; color: #606060;
    cursor: pointer;
    flex-shrink: 0;
    transition: all 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

.nav-dot:hover { background: rgba(255, 255, 255, 0.1); border-color: rgba(255, 255, 255, 0.2); transform: translateY(-2px); }

.nav-dot.answered {
    background: rgba(66, 215, 184, 0.15);
    color: var(--accent-teal);
    border-color: rgba(66, 215, 184, 0.4);
    box-shadow: inset 0 0 10px rgba(66, 215, 184, 0.1);
}

.nav-dot.flagged {
    border-color: #ffab40;
    color: #ffab40;
    box-shadow: 0 0 15px rgba(255, 171, 64, 0.2);
}

.nav-dot.answered.flagged {
    background: linear-gradient(135deg, rgba(66, 215, 184, 0.2), rgba(255, 171, 64, 0.2));
}

/* --- THE WIDE FEED --- */
.exam-viewport {
    flex: 1;
    overflow-y: auto;
    padding: 0 1.5rem;
}

.q-row {
    padding: 1.5rem 0;
    border-bottom: 1px solid rgba(255, 255, 255, 0.06);
    display: flex;
    flex-direction: column;
    gap: 12px;
}

.q-meta {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.q-label { font-weight: 700; font-size: 0.75rem; color: var(--accent-teal); text-transform: uppercase; }

.q-actions { display: flex; gap: 15px; }
.q-actions button { background: none; border: none; color: #707070; font-size: 0.9rem; cursor: pointer; }
.q-actions button.active { color: #ffab40; }
.q-actions button.hint { color: var(--cyber-gold); }

.q-text {
    font-family: 'Newsreader', serif;
    font-size: 1.1rem;
    line-height: 1.5;
    color: #fff;
}

.options-cluster {
    display: grid;
    grid-template-columns: 1fr 1fr; 
    gap: 12px;
}

.options-cluster.vertical-layout {
    grid-template-columns: 1fr;
}

.opt-wrapper {
    position: relative;
}

.opt-btn {
    background: rgba(255, 255, 255, 0.08);
    border: 1px solid rgba(255, 255, 255, 0.15);
    padding: 14px 16px;
    border-radius: 14px;
    display: flex;
    align-items: center;
    gap: 12px;
    cursor: pointer;
    transition: all 0.2s ease;
}

.opt-btn span {
    font-size: 0.9rem;
    color: #d0d0d0;
    line-height: 1.4;
}

.opt-indicator {
    width: 16px; height: 16px;
    border-radius: 50%;
    border: 2px solid #888;
    flex-shrink: 0;
    background: rgba(0,0,0,0.2);
}

.opt-wrapper input:checked + .opt-btn {
    background: rgba(66, 215, 184, 0.05);
    border-color: var(--accent-teal);
}

.opt-wrapper input:checked + .opt-btn .opt-indicator {
    border-color: var(--accent-teal);
    background: var(--accent-teal);
    box-shadow: 0 0 8px var(--accent-teal);
}

.opt-wrapper input:checked + .opt-btn span { color: #fff; }

/* --- FOOTER --- */
.session-footer {
    padding: 1.25rem 1.5rem calc(1rem + env(safe-area-inset-bottom));
    background: #050505;
    border-top: 1px solid rgba(255, 255, 255, 0.08);
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.session-progress-block { flex: 1; margin-right: 2rem; }
.p-text { display: flex; justify-content: space-between; font-size: 0.7rem; color: #707070; margin-bottom: 6px; }
.p-track { height: 6px; background: rgba(255, 255, 255, 0.05); border-radius: 3px; position: relative; overflow: hidden; }
.p-bar-fill { height: 100%; background: var(--accent-teal); border-radius: 3px; box-shadow: 0 0 15px rgba(66, 215, 184, 0.4); transition: width 0.6s cubic-bezier(0.34, 1.56, 0.64, 1); position: absolute; left: 0; top: 0; z-index: 2; }
.p-bar-flagged { height: 100%; background: #ffab40; opacity: 0.4; transition: width 0.6s ease, left 0.6s ease; position: absolute; top: 0; z-index: 1; }

.finish-exam-btn {
    background: var(--accent-teal);
    color: #050505;
    border: none;
    padding: 10px 24px;
    border-radius: 10px;
    font-weight: 700;
    font-size: 0.85rem;
    cursor: pointer;
    box-shadow: 0 4px 15px rgba(66, 215, 184, 0.2);
}

@media (min-width: 900px) {
    .exam-viewport { padding: 0 20%; }
    /* On desktop, still prefer 2 columns for better readability unless vertical is forced */
    .options-cluster { grid-template-columns: 1fr 1fr; column-gap: 20px; }
    .options-cluster.vertical-layout { grid-template-columns: 1fr; }
    .q-text { font-size: 1.25rem; }
}`; document.head.appendChild(s);

