 443 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 444 |                     const sentenceEndRegex = /[.!?]/;
 445 |                     
 446 |                     // Helper: TreeWalker for linear text traversal within the page
 447 |                     function createWalker(root) {
 448 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 449 |                     }
 450 | 
 451 |                     // 1. BACKWARD SCAN (Find start)
 452 |                     let currentStartNode = startNode;
 453 |                     let currentStartOffset = startOffset;
 454 |                     let finalStartNode = startNode;
 455 |                     let finalStartOffset = 0;
 456 | 
 457 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 458 |                     let lastPuncIndex = -1;
 459 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 460 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 461 |                     }
 462 | 
 463 |                     if (lastPuncIndex !== -1) {
 464 |                         finalStartOffset = lastPuncIndex + 1;
 465 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 466 |                     } else {
 467 |                         const walker = createWalker(pageBoundary);
 468 |                         walker.currentNode = currentStartNode;
 469 |                         let prevNode = walker.previousNode();
 470 |                         let foundStart = false;
 471 | 
 472 |                         while (prevNode && !foundStart) {
 473 |                             const text = prevNode.textContent;
 474 |                             for (let i = text.length - 1; i >= 0; i--) {
 475 |                                 if (sentenceEndRegex.test(text[i])) {
 476 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 477 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 478 |                                     foundStart = true; break;
 479 |                                 }
 480 |                             }
 481 |                             if (!foundStart) {
 482 |                                 finalStartNode = prevNode; finalStartOffset = 0;
 483 |                                 prevNode = walker.previousNode();
 484 |                             }
 485 |                         }
 486 |                     }
 487 | 
 488 |                     // 2. FORWARD SCAN (Find end)
 489 |                     let currentEndNode = startNode;
 490 |                     let currentEndOffset = startOffset;
 491 |                     let finalEndNode = startNode;
 492 |                     let finalEndOffset = startNode.textContent.length;
 493 | 
 494 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 495 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 496 | 
 497 |                     if (nextPuncIndex !== -1) {
 498 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 499 |                     } else {
 500 |                         const walker = createWalker(pageBoundary);
 501 |                         walker.currentNode = currentEndNode;
 502 |                         let nextNode = walker.nextNode();
 503 |                         let foundEnd = false;
 504 | 
 505 |                         while (nextNode && !foundEnd) {
 506 |                             const text = nextNode.textContent;
 507 |                             const puncIdx = text.search(sentenceEndRegex);
 508 |                             if (puncIdx !== -1) {
 509 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 510 |                                 foundEnd = true;
 511 |                             } else {
 512 |                                 finalEndNode = nextNode; finalEndOffset = text.length;
 513 |                                 nextNode = walker.nextNode();
 514 |                             }
 515 |                         }
 516 |                     }
 517 | 
 518 |                     // Create the final Range
 519 |                     const r = rootDoc.createRange();
 520 |                     try {
 521 |                         r.setStart(finalStartNode, finalStartOffset);
 522 |                         r.setEnd(finalEndNode, finalEndOffset);
 523 |                         return r;
 524 |                     } catch (e) {
 525 |                         console.warn("Sentence Range Error:", e);
 526 |                         return null;
 527 |                     }
 528 |                 }
 529 |             } catch (err) {
 530 |                 console.error("Iframe Load Error:", err);
 531 |             }
 532 |         }, 100);
 533 |     };
