let targetY = sentenceBottom + 15;

// If it hits the bottom of the screen, try above
if (targetY + menuHeight > window.innerHeight - 20) {
    targetY = sentenceTop - menuHeight - 15;
}

// Failsafe: If trying to place above pushes it off the top (negative Y),
// force it back to below and let the user drag it if needed
if (targetY < 10) {
    targetY = sentenceBottom + 15;
}

