    x: Math.max(10, Math.min(window.innerWidth - menuWidth - 10, sentenceCenterX - (menuWidth / 2))),
    y: Math.max(10, Math.min(window.innerHeight - menuHeight - 20, targetY)),
    text: result.text
});

